head.script:
scwin.hid_repClntNo = ""; // 대표거래처번호
scwin.hid_wrkPlCd = ""; // 작업장코드

scwin.wrkPlCd = "999";	// 작업장코드

scwin.sheetTitle = "";

//-------------------------------------------------------------------------
// 컴포넌트 이벤트
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    lc_dtCondition.setSelectedIndex(0);
    gr_InIntendInformation.setColumnVisible('selpchItemNm', false);
    gr_InIntendInformation.setColumnVisible('dptWrkPlCd', false);
    gr_InIntendInformation.setColumnVisible('tplZip', true);
    gr_InIntendInformation.setColumnVisible('osideCdNm', true);
    gr_InIntendInformation.setColumnVisible('ioDt', true);
    gr_InIntendInformation.setColumnVisible('selfVehclNo', true);
};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------    
scwin.onUdcCompleted = function () {
    ed_clntNo.setValue("000001");
    txt_clntNm.setValue("보랄석고보드시스템");
    ed_srchWrkStDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    ed_srchWrkEndDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    lc_dtCondition.setSelectedIndex(1);
}

//-------------------------------------------------------------------------
// 사용자 함수
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    // 거래처 선택 확인
    if ($c.gus.cfIsNull(ed_clntNo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("거래처"));
        ed_clntNo.focus();
        return false;

    }

    // if (!$c.gus.cfValidate(ed_srchWrkStDt) || !$c.gus.cfValidate(ed_srchWrkEndDt)) {
    //     return;
    // }

    if (ed_srchWrkStDt.getValue() == "") {
        await $c.win.alert("작업 조회 시작일자은(는) 필수 입력 항목입니다.");
        ed_srchWrkStDt.focus();
        return;
    }

    if (ed_srchWrkEndDt.getValue() == "") {
        await $c.win.alert("작업 조회 종료일자은(는) 필수 입력 항목입니다.");
        ed_srchWrkEndDt.focus();
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_srchWrkStDt.getValue(), ed_srchWrkEndDt.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_srchWrkStDt.focus();
        return;
    }
    $c.sbm.execute(sbm_retrieve);

    // document.getElementById('tr_grid1').style.display = "";
    // document.getElementById('tr_grid1_ttrows').style.display = "";
    // document.getElementById('tr_grid2').style.display = "none";
    // document.getElementById('tr_grid2_ttrows').style.display = "none";
    // document.getElementById('tr_grid3').style.display = "none";
    // document.getElementById('tr_grid3_ttrows').style.display = "none";
}

scwin.f_runExcel = async function () {
    debugger;
    fileName = "크나우프 운송비조회";
    let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) $c.data.downloadGridViewExcel(gr_InIntendInformation, { fileName: fileName, sheetName: fileName });
}

scwin.f_closingData = async function (varGrNm) {
    //마감자료 다운로드 (운송비+휴일/예외운송비 적용)  
    var yyyyMm = (ed_srchWrkStDt.getValue()).substring(0, 8);
    scwin.sheetTitle = yyyyMm + "_크나우프운송비마감자료";
    cfrm = await $c.win.confirm(yyyyMm.substring(0, 4) + "년 " + yyyyMm.substring(4, 6) + "월 마감자료를 EXCEL로 다운로드 받으시겠습니까?");

    if (cfrm) {
        ds_Query.set('closingDataGb', "1");
        $c.sbm.execute(sbm_retrieveClosingData);
    }
}

scwin.f_closingData2 = async function (varGrNm) {
    //마감자료 다운로드 (조회기간에 따른 운송비자료 조회 - 전월예외운송비 제외)
    var yyyyMm = (ed_srchWrkStDt.getValue()).substring(0, 8);

    scwin.sheetTitle = yyyyMm + "_크나우프운송비마감자료2";
    cfrm = await $c.win.confirm("조회기간에 따른 자료를 EXCEL로 다운로드 받으시겠습니까?");

    if (cfrm) {
        ds_Query.set('closingDataGb', "2");
        $c.sbm.execute(sbm_retrieveClosingData);
    }
}

scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
}

scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    var pWhere;		// 조회조건

    switch (disGubun) {
        case 1:

            // 거래처 팝업			
            udc_clnt.setSelectId("retrieveClntInfo2");
            udc_clnt.cfCommonPopUp(scwin.udc_clnt_callbackFunc
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "계약 거래처,거래처코드,거래처명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        case 2:
            // 사업장 팝업	
            var v_clntNo = ed_clntNo.getValue();
            var v_itemCd = "BIZ";	// 사업장 조회
            var v_wrkPlCd = scwin.wrkPlCd;

            // 거래처 선택 확인
            if ($c.gus.cfIsNull(v_clntNo)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("거래처"));
                ed_clntNo.focus();
                return false;
            }

            pWhere = v_clntNo + "," + v_itemCd + "," + v_wrkPlCd;
            udc_bizLong.setSelectId("retrieveEdiMapping");
            udc_bizLong.cfCommonPopUp(scwin.udc_bizLong_callbackFunc
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "사업장,사업장코드,사업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

    }
}

scwin.udc_clnt_callbackFunc = function (rtnList) {
    //거래처코드  거래처명
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, txt_clntNm, [scwin.hid_repClntNo]);

    if ($c.gus.cfIsNull(scwin.hid_repClntNo)) scwin.hid_repClntNo = ed_clntNo.getValue();
}

scwin.udc_bizLong_callbackFunc = function (rtnList) {
    //도착지코드          도착지명
    $c.gus.cfSetReturnValue(rtnList, ed_bizLongCd, txt_bizLongNm);
}

scwin.setSeq = function (d, fd, r, c) {
    return d == "0" ? "" : d;
}
//-------------------------------------------------------------------------
// 컴포넌트 이벤트
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function (e) {
    ed_clntNo.setValue("");
    txt_clntNm.setValue("");
    ed_bizLongCd.setValue("");
    txt_bizLongNm.setValue("");
    ed_srchWrkStDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    ed_srchWrkEndDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    lc_dtCondition.setSelectedIndex(0);
    lc_condition.setSelectedIndex(0);
};

scwin.sbm_retrieve_submitdone = function (e) {
    rowCnt = ds_Present.getTotalRow();
    if (rowCnt < 1) {
        $c.win.alert("조회된 데이터가 없습니다.");
        return;
    } else {
        ed_totCnt.setValue(rowCnt);
    }
}

scwin.sbm_retrieveClosingData_submitdone = function (e) {
    totCnt = ds_closingData.getTotalRow();
    if (totCnt != 0) {
        const infoArr = [];
        const options = {
            fileName: scwin.sheetTitle //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        };
        $c.data.downloadGridViewExcel(gr_closingData, options, infoArr);
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
}

scwin.setSellUpr = function(d) {
    if(d == 0) return "예외운송";
    return Number(d).toFixed(2);

}

scwin.btn_excel1_onclick = function (e) {
    scwin.f_closingData2();
};

scwin.btn_excel2_onclick = function (e) {
    scwin.f_closingData();
};

scwin.lc_condition_onchange = function (info) {
    if (lc_condition.getSelectedIndex() == 1) {
        gr_InIntendInformation.setColumnVisible('tplZip', false);
        gr_InIntendInformation.setColumnVisible('osideCdNm', false);
        gr_InIntendInformation.setColumnVisible('ioDt', false);
        gr_InIntendInformation.setColumnVisible('selfVehclNo', false);
        gr_InIntendInformation.setColumnVisible('selpchItemNm', true);
        gr_InIntendInformation.setColumnVisible('dptWrkPlCd', true);
    } else {
        gr_InIntendInformation.setColumnVisible('selpchItemNm', false);
        gr_InIntendInformation.setColumnVisible('dptWrkPlCd', false);
        gr_InIntendInformation.setColumnVisible('tplZip', true);
        gr_InIntendInformation.setColumnVisible('osideCdNm', true);
        gr_InIntendInformation.setColumnVisible('ioDt', true);
        gr_InIntendInformation.setColumnVisible('selfVehclNo', true);
    }
};

scwin.udc_clnt_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, txt_clntNm, 1);
};

scwin.udc_bizLong_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_bizLongCd, txt_bizLongNm, 2);
};

scwin.udc_clnt_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), txt_clntNm.getValue(), 'F', 'F');
};

scwin.udc_bizLong_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_bizLongCd.getValue(), txt_bizLongNm.getValue(), 'F', 'F');
};

scwin.udc_clnt_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(txt_clntNm, ed_clntNo, 1, false);
};

scwin.udc_bizLong_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(txt_bizLongNm, ed_bizLongCd, 2, false);
};
